import{_ as a,c as t,o as r,aj as o}from"./chunks/framework.guNMSiFm.js";const m=JSON.parse('{"title":"Iroha 3 vs. Iroha 2","description":"","frontmatter":{},"headers":[],"relativePath":"get-started/iroha-2.md","filePath":"get-started/iroha-2.md","lastUpdated":1777621302000}'),i={name:"get-started/iroha-2.md"};function n(s,e,d,l,h,c){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="iroha-3-vs-iroha-2" tabindex="-1">Iroha 3 vs. Iroha 2 <a class="header-anchor" href="#iroha-3-vs-iroha-2" aria-label="Permalink to &quot;Iroha 3 vs. Iroha 2&quot;">​</a></h1><p>The current workspace ships two deployment tracks from the same codebase:</p><ul><li><strong>Iroha 2</strong> for self-hosted permissioned and consortium networks</li><li><strong>Iroha 3 / SORA Nexus</strong> for the Nexus-oriented global deployment track</li></ul><p>Iroha 3 is not a separate rewrite. It reuses the same core crates, the same Iroha Virtual Machine, the same Torii transport layer, and the same Norito codec.</p><h2 id="what-stays-the-same" tabindex="-1">What Stays the Same <a class="header-anchor" href="#what-stays-the-same" aria-label="Permalink to &quot;What Stays the Same&quot;">​</a></h2><ul><li><code>irohad</code>, <code>iroha</code>, and <code>kagami</code> remain the primary operator tools</li><li>smart contracts still target IVM</li><li>Torii remains the main API surface</li><li>Sumeragi remains the consensus engine</li><li>Norito remains the canonical wire format</li></ul><h2 id="what-changes-in-iroha-3" tabindex="-1">What Changes in Iroha 3 <a class="header-anchor" href="#what-changes-in-iroha-3" aria-label="Permalink to &quot;What Changes in Iroha 3&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Area</th><th>Iroha 2</th><th>Iroha 3</th></tr></thead><tbody><tr><td>Deployment model</td><td>Standalone self-hosted networks</td><td>Nexus-oriented deployment track with SORA-specific profiles</td></tr><tr><td>Execution layout</td><td>Single-lane worldview</td><td>Multi-lane execution with Nexus data spaces</td></tr><tr><td>Routing</td><td>One network surface</td><td>Lane and data-space aware routing policies</td></tr><tr><td>Consensus profile</td><td>Permissioned by default</td><td>Permissioned or NPoS depending on the dataspace and profile</td></tr><tr><td>Operator config</td><td>Generic defaults</td><td>Additional Nexus, SoraFS, streaming, and lane catalog settings</td></tr><tr><td>Genesis workflow</td><td>Standard manifest and signed block</td><td>Same workflow, plus explicit <code>consensus_mode</code>, topology PoPs, and Nexus-oriented profiles</td></tr></tbody></table><h2 id="migration-guidance" tabindex="-1">Migration Guidance <a class="header-anchor" href="#migration-guidance" aria-label="Permalink to &quot;Migration Guidance&quot;">​</a></h2><p>If you already know Iroha 2, the main operational differences in Iroha 3 are:</p><ul><li>you should expect more configuration around Nexus lanes and data spaces</li><li>public SORA Nexus deployments use the <code>--sora</code> profile path</li><li>genesis manifests now carry more explicit consensus and crypto metadata</li><li>telemetry and Torii reference pages matter more during rollout because operator status endpoints are part of the day-to-day workflow</li></ul><p>The shared codebase means many concepts stay familiar, but the deployment shape changes from &quot;run your own isolated network&quot; to &quot;run the Nexus-oriented track with lane-aware configuration and tooling.&quot;</p><h2 id="read-next" tabindex="-1">Read Next <a class="header-anchor" href="#read-next" aria-label="Permalink to &quot;Read Next&quot;">​</a></h2><ul><li><a href="/iroha-2-docs/get-started/launch-iroha-2.html">Launch Iroha 3</a></li><li><a href="/iroha-2-docs/reference/genesis.html">Genesis reference</a></li><li><a href="/iroha-2-docs/blockchain/iroha-explained.html">Iroha 3 architecture overview</a></li></ul>',14)])])}const p=a(i,[["render",n]]);export{m as __pageData,p as default};
